import Mathlib

inductive Bool
| false : Bool
| true : Bool

theorem main : Bool :=
begin
  let i := 0,
  let j := 0,
  have h1 : i < 100 := by linarith,
  while h1 do
    let j := 0,
    while j < 1 do
      let j := j + 1,
    end,
    let i := i + 0,
  end,
  return Bool.true,
end

theorem check_property : main = Bool.true :=
begin
  exact rfl,
end
